const kpi = $json.kpi;
const t1 = kpi.tier1_business;
const t2 = kpi.tier2_operational;
const t3 = kpi.tier3_cost;

const date = new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'short', year: 'numeric' });

// Format percentages
const pct = (v) => v !== null && v !== undefined ? (v * 100).toFixed(1) + '%' : 'n/a';
const usd = (v) => v !== null && v !== undefined ? '$' + v.toFixed(2) : 'n/a';

// Count bugs fixed (from pipeline completions of bug-fix type)
const bugFixPipelines = Object.keys(t2.avgPipelineDuration)
  .filter(k => k === 'bug-fix')
  .reduce((sum, k) => sum + (t2.avgPipelineDuration[k].count || 0), 0);

// Top 5 agents by volume
const agentEntries = Object.entries(t2.agentSuccessRate)
  .sort((a, b) => b[1].total - a[1].total)
  .slice(0, 5);

const agentLines = agentEntries.map(([name, data]) => {
  const rate = (data.rate * 100).toFixed(0);
  return `  ${name}: ${data.total} jobs (${rate}% pass)`;
}).join('\n');

// Needs Attention section
const issues = [];
if (t2.stalledJobs && t2.stalledJobs.length > 0) {
  issues.push(`${t2.stalledJobs.length} stalled job(s)`);
}
if (t2.pipelineCompletionRate !== null && t2.pipelineCompletionRate < 0.8) {
  issues.push(`Pipeline completion rate low: ${pct(t2.pipelineCompletionRate)}`);
}
if (t2.reworkRate !== null && t2.reworkRate > 0.2) {
  issues.push(`High rework rate: ${pct(t2.reworkRate)}`);
}
if (t1.humanInterventionRate > 0.15) {
  issues.push(`Human intervention rate: ${pct(t1.humanInterventionRate)}`);
}
if (t3.wastedSpend > 0.15) {
  issues.push(`Wasted spend: ${pct(t3.wastedSpend)}`);
}

const attentionBlock = issues.length > 0
  ? issues.map(i => `  ⚠ ${i}`).join('\n')
  : '  All clear';

const message = `*Daily Digest - ${date}*

*Shipped*
Features: ${t1.featuresShipped} | Bugs fixed: ${bugFixPipelines} | Pipeline completion: ${pct(t2.pipelineCompletionRate)}

*Quality*
QG first-pass: ${pct(t2.firstPassQualityGateRate)} | Rework rate: ${pct(t2.reworkRate)} | Stalled: ${t2.stalledJobs ? t2.stalledJobs.length : 0}

*Cost*
Today: ${usd(t3.dailySpend)} | This week: ${usd(t3.weeklySpend)} | Per feature: ${usd(t2.costPerFeature)}

*Agent Performance*
${agentLines || '  No agent data'}

*Needs Attention*
${attentionBlock}`;

return [{ json: { message } }];
